import { Outlet, Link } from "react-router-dom";
import { makeStyles } from "@material-ui/core/styles";
import { NavLink } from "react-router-dom";
import "./Home.css";
import sa from "./sa.svg";

const useStyles = makeStyles((theme) => ({
  options: {
    marginLeft: "40px",
    color: "white",
  },
}));

const Layout = () => {
  const classes = useStyles();

  return (
    <>
      <div
        style={{
          position: "absolute",
          backgroundColor: "black",
          height: "70px",
          width: "100%",
          top: 0,
        }}
      >
        <div
          style={{
            // marginRight: "150px",
            padding: "0 150px",
            // float: "right",
            lineHeight: "70px",
            display: "flex",
            // width: "100%",
            justifyContent: "space-between",
          }}
        >
          <div>
            <span
              className="menu-items"
              // className="menu-items"
              style={{
                width: "100px",
                textAlign: "center",
                display: "flex",
                justifySelf: "flex-start",
                // marginRight: "800px",
              }}
            >
              <NavLink
                to="/"
                style={{
                  display: "block",
                  height: "100%",
                  color: "white",
                  textDecoration: "none",
                }}
                activeclassname="active"
              >
                <img
                  src={sa}
                  alt="logo"
                  style={{ width: 40, height: 40, marginBottom: -10 }}
                ></img>
              </NavLink>
            </span>
          </div>
          <div>
            <span
              className="menu-items hover-underline-animation"
              // className="menu-items"
              style={{ width: "100px", textAlign: "center" }}
            >
              <NavLink
                to="/about"
                activeclassname="active"
                style={{
                  display: "block",
                  height: "100%",
                  color: "white",
                  textDecoration: "none",
                }}
              >
                About
              </NavLink>
            </span>

            <span
              className="menu-items hover-underline-animation"
              // className="menu-items"
              style={{ width: "100px", textAlign: "center" }}
            >
              <NavLink
                to="/work"
                activeclassname="active"
                style={{
                  display: "block",
                  height: "100%",
                  color: "white",
                  textDecoration: "none",
                }}
              >
                Work
              </NavLink>
            </span>
            <span
              className="menu-items hover-underline-animation"
              // className="menu-items"
              style={{ width: "100px", textAlign: "center" }}
            >
              <NavLink
                to="/art"
                activeclassname="active"
                style={{
                  display: "block",
                  height: "100%",
                  color: "white",
                  textDecoration: "none",
                }}
              >
                Art
              </NavLink>
            </span>
            <span
              className="menu-items hover-underline-animation"
              // className="menu-items"
              style={{ width: "100px", textAlign: "center" }}
            >
              <NavLink
                activeclassname="active"
                to="/contact"
                style={{
                  display: "block",
                  height: "100%",
                  color: "white",
                  textDecoration: "none",
                }}
              >
                contact
              </NavLink>
            </span>
          </div>
        </div>
      </div>

      <Outlet />
    </>
  );
};

export default Layout;
